INSERT INTO guides (guide_id, title, slug, description, theme_id, engagement_level, source_url, display_order, sections) VALUES

('GUIDE_001',
 'Your Voice Matters: How to Contact Houston Officials',
 'connecting-with-officials',
 'A complete guide to contacting your elected officials at every level — city, county, state, and federal. Includes phone scripts, email templates, and a civic engagement checklist.',
 'THEME_04',
 'Off the Couch',
 'https://www.thechangelab.net/connecting-with-your-elected-officials',
 1,
 '[{"id":"s1","title":"Houston City Council","content":"<p>Houston has 16 elected leaders on City Council managing the municipal budget, laws, services, and zoning.</p><p><strong>Main line:</strong> (832) 393-1100</p><p><strong>Address:</strong> 900 Bagby, Houston, TX 77002</p><p>You can register to speak at public meetings. Check the council agenda and sign up before the deadline.</p>"},{"id":"s2","title":"Harris County Commissioners Court","content":"<p>The County Judge plus 4 Commissioners oversee the county budget, health services, sheriff''s department, flood control, and emergency management.</p><p><strong>Address:</strong> 1001 Preston, Suite 610, Houston, TX 77002</p><p>Register online for public comment through the county clerk''s portal.</p>"},{"id":"s3","title":"Texas State Legislature","content":"<p>Your state representative and senator handle state laws, education funding, healthcare, criminal justice, and infrastructure.</p><p>Use the <strong>Who Represents Me?</strong> tool at capitol.texas.gov to find your legislators.</p><p><strong>Tip:</strong> Time your calls during legislative session (January–May) for maximum impact. Always mention the bill number.</p>"},{"id":"s4","title":"U.S. Congress","content":"<p>Texas has 2 U.S. Senators and 38 Representatives handling federal legislation, budget, immigration, Medicare/Medicaid, Social Security, and foreign policy.</p><p>Find your representative by zip code at house.gov. Contact senators via senate.gov.</p><p><strong>Best practice:</strong> Mention that you are a constituent and reference specific bill numbers.</p>"},{"id":"s5","title":"Texas Governor & Statewide Officials","content":"<p>The Governor, Lieutenant Governor, Attorney General, and Comptroller each handle different aspects of state governance.</p><p><strong>Governor Hotline:</strong> (512) 463-2000</p><p><strong>Address:</strong> P.O. Box 12428, Austin, TX 78711-2428</p>"},{"id":"s6","title":"Best Practices for Effective Communication","content":"<p><strong>7 Keys:</strong></p><ol><li>Be a constituent — contact only YOUR representatives</li><li>Be specific — mention bill numbers</li><li>Be brief — under 3 minutes for calls</li><li>Be personal — share how issues affect you</li><li>Be polite</li><li>Be persistent</li><li>Be consistent — multiple constituents create momentum</li></ol><p>Phone calls carry 3x the weight of emails. Every single call is logged and counted.</p>"},{"id":"s7","title":"Templates","content":"<p><strong>Phone Script:</strong> \"Hi, my name is [NAME] and I''m a constituent from [CITY/ZIP]. I''m calling about [BILL/ISSUE]. I would like [Representative/Senator NAME] to [YOUR ASK]. This matters to me because [PERSONAL REASON]. Thank you for your time.\"</p><p><strong>Email Template:</strong> Use a clear subject line with the bill number. Include your address to verify constituent status. Keep to 3 paragraphs: who you are, what you want, why it matters.</p>"}]'::jsonb),

('GUIDE_002',
 'Houston Voter Guide',
 'houston-voter-guide',
 'Everything you need to vote in federal, Texas, Harris County, and Houston elections. Registration, ID requirements, key dates, and FAQ.',
 'THEME_04',
 'On the Couch',
 'https://www.thechangelab.net/houston-voter-guide',
 2,
 '[{"id":"s1","title":"Getting Started","content":"<p><strong>Four steps to vote:</strong></p><ol><li><strong>Check Eligibility</strong> — U.S. citizen, Texas resident, 18+ by election day</li><li><strong>Register</strong> — at votetexas.gov, deadline is 30 days before election</li><li><strong>Gather ID</strong> — Texas driver''s license, passport, military ID, or other approved photo ID</li><li><strong>Vote</strong> — find your polling location at harrisvotes.com</li></ol>"},{"id":"s2","title":"Key Dates","content":"<p>Registration deadline: 30 days before election</p><p>Mail ballot application: 11 days before election</p><p>Early voting: October 20 – November 1, 2025</p><p>Election Day: November 4, 2025</p><p>Mail ballot return: by 7 PM on Election Day</p>"},{"id":"s3","title":"How to Vote In Person","content":"<p>Bring approved photo ID. Polls open 7 AM – 7 PM. During early voting, you can vote at ANY location in Harris County. On Election Day, go to your assigned precinct.</p>"},{"id":"s4","title":"How to Vote by Mail","content":"<p><strong>Eligible if:</strong> 65+, disabled, out of county during election period, or incarcerated (pre-trial).</p><p>Apply for ballot → Receive by mail → Complete and sign → Return by 7 PM Election Day.</p>"},{"id":"s5","title":"FAQ","content":"<p><strong>I just moved — can I still vote?</strong> If you moved within the county, you can vote at your new precinct. Update your registration.</p><p><strong>I have a felony conviction.</strong> In Texas, you can vote after completing your full sentence including parole/probation.</p><p><strong>I don''t have an acceptable ID.</strong> You can sign a Reasonable Impediment Declaration and use an alternative form of ID.</p><p><strong>Can I bring notes into the booth?</strong> Yes, you can bring written notes or use your phone for reference.</p>"},{"id":"s6","title":"Quick Contacts","content":"<p><strong>Texas Election Hotline:</strong> 1-800-252-VOTE</p><p><strong>Harris County Elections:</strong> harrisvotes.com</p><p><strong>Registration Status:</strong> hctax.net</p>"}]'::jsonb),

('GUIDE_003',
 '2025 U.S. Civic Landscape Report',
 'civic-landscape-report',
 'A data-driven look at America''s volunteer sector and organizational ecosystem. 75.7 million volunteers, 4.99 billion hours, 1.88 million nonprofits.',
 'THEME_07',
 'On the Couch',
 'https://www.thechangelab.net/2025-us-civic-landscape-report',
 3,
 '[{"id":"s1","title":"Executive Highlights","content":"<p><strong>75.7 million</strong> neighbors volunteered</p><p><strong>4.99 billion</strong> volunteer hours annually</p><p><strong>12.8 million</strong> nonprofit employment</p><p><strong>90,837</strong> local governments</p>"},{"id":"s2","title":"Organization Landscape by Focus Area","content":"<ul><li>Community, Culture & Belonging: 729,842 orgs</li><li>Education & Opportunity: 397,367</li><li>Basic Needs & Economic Security: 298,214</li><li>Systems Change & Structural Power: 201,498</li><li>Health, Wellness & Care: 112,461</li><li>Environment & Infrastructure: 97,946</li><li>Governance, Rights & Democracy: 40,481</li></ul>"},{"id":"s3","title":"Methodology","content":"<p>Data sourced from IRS/NTEE classification system, Bureau of Labor Statistics, AmeriCorps, U.S. Census Bureau, and Federal Reserve Economic Data (FRED).</p>"}]'::jsonb),

('GUIDE_004',
 'Starting a Neighborhood Action Group',
 'neighborhood-action-group',
 'A 9-step guide to building a community organizing effort in your neighborhood. From picking your issue to running meetings and building power.',
 'THEME_03',
 'Use Your Superpower',
 'https://www.thechangelab.net/neighborhood-action-group',
 4,
 '[{"id":"s1","title":"Pick Your Issue","content":"<p>Identify a specific neighborhood problem: safety, housing, environment, or services. Talk to your neighbors — what keeps coming up?</p>"},{"id":"s2","title":"Find Your Team","content":"<p>Recruit 3–5 committed core members. Look for people who are already talking about the issue — at the school pickup line, at the corner store, on Nextdoor.</p>"},{"id":"s3","title":"Hold Your First Meeting","content":"<p>Keep it small and informal. Set a clear agenda: what''s the problem, what do we want, who can help? Assign roles: note-taker, facilitator, outreach lead.</p>"},{"id":"s4","title":"Get More People","content":"<p>Door-knock your block. Post on social media. Host a community cookout. Every person you add multiplies your power.</p>"},{"id":"s5","title":"Make Your Plan","content":"<p>Set specific, achievable objectives. \"We want speed bumps on Oak Street by June\" is better than \"we want safer streets.\" Identify who has the power to give you what you want.</p>"},{"id":"s6","title":"Run Good Meetings","content":"<p>Start and end on time. Have an agenda. Let everyone speak. End with clear next steps and who''s responsible for each.</p>"},{"id":"s7","title":"Keep Everyone Updated","content":"<p>Use a group text, email list, or WhatsApp group. Share wins, no matter how small. People stay engaged when they see progress.</p>"},{"id":"s8","title":"Build Power and Win","content":"<p>Show up in numbers to public meetings. Tell your story to the media. The Oak Street Safety Team got speed bumps in six months by showing up to three council meetings with 20+ neighbors each time.</p>"},{"id":"s9","title":"Avoid Common Problems","content":"<p>Watch for burnout — rotate responsibilities. Avoid mission creep — stay focused on your issue. Handle internal conflicts early and directly.</p>"}]'::jsonb),

('GUIDE_005',
 'Connecting with Local Resources',
 'connecting-with-resources',
 'A directory of Houston''s essential services organized by need: housing, food, healthcare, employment, legal aid, immigration, LGBTQIA support, and utilities.',
 'THEME_02',
 'On the Couch',
 'https://www.thechangelab.net/connecting-with-local-resources',
 5,
 '[{"id":"s1","title":"Housing","content":"<p><strong>Coalition for the Homeless:</strong> 713-739-7514</p><p><strong>Houston Housing Authority:</strong> houstonha.org</p><p><strong>Avenue CDC:</strong> avenuecdc.org — affordable housing and homebuyer education</p>"},{"id":"s2","title":"Food","content":"<p><strong>Houston Food Bank:</strong> houstonfoodbank.org — 800,000+ people served monthly</p><p><strong>Bread of Life:</strong> 713-993-7777</p><p><strong>SNAP Benefits:</strong> Apply at yourtexasbenefits.com</p>"},{"id":"s3","title":"Healthcare","content":"<p><strong>Legacy Community Health:</strong> legacycommunityhealth.org — sliding scale fees</p><p><strong>Harris Health System:</strong> harrishealth.org — county hospital system</p><p><strong>Mental Health America of Greater Houston:</strong> mhahouston.org</p>"},{"id":"s4","title":"Employment","content":"<p><strong>Workforce Solutions:</strong> wrksolutions.com — job search, training, career services</p><p><strong>BakerRipley:</strong> bakerripley.org — workforce development</p><p><strong>Project HOPE:</strong> Emergency financial assistance</p>"},{"id":"s5","title":"Legal Services","content":"<p><strong>Lone Star Legal Aid:</strong> lonestarlegal.org — free legal help</p><p><strong>Houston Volunteer Lawyers:</strong> hvlaporg — pro bono legal services</p>"},{"id":"s6","title":"Immigration","content":"<p><strong>RAICES:</strong> raicestexas.org</p><p><strong>Catholic Charities:</strong> catholiccharities.org</p><p><strong>Alliance for Multicultural Community Services:</strong> allianceontheweb.org</p>"},{"id":"s7","title":"LGBTQIA+ Support","content":"<p><strong>Montrose Center:</strong> montrosecenter.org</p><p><strong>Legacy LGBTQ Health:</strong> legacycommunityhealth.org</p><p><strong>PFLAG Houston:</strong> pflaghouston.org</p>"},{"id":"s8","title":"Utilities Assistance","content":"<p><strong>LIHEAP:</strong> Low Income Home Energy Assistance</p><p><strong>United Way 2-1-1:</strong> Dial 211 for any social service need</p><p><strong>Catholic Charities:</strong> Utility bill assistance programs</p>"}]'::jsonb),

('GUIDE_006',
 'Make Your Voice Heard: Civic Action Guide',
 'make-your-voice-heard',
 'A step-by-step guide to civic participation — from a 15-minute quick start to a 30-day action plan. Find your representatives, make calls, and attend meetings.',
 'THEME_04',
 'Off the Couch',
 'https://www.thechangelab.net/new-make-your-voice',
 6,
 '[{"id":"s1","title":"Why Your Voice Matters","content":"<p>Every call to your representative is logged and counted. Staff track constituent contacts and report them directly to the elected official. Volume creates pressure — when enough people call about the same issue, it moves to the top of the priority list.</p>"},{"id":"s2","title":"15-Minute Quick Start","content":"<ol><li><strong>Find your representatives</strong> — use house.gov and senate.gov</li><li><strong>Make one phone call</strong> — pick the issue you care most about</li><li><strong>Save the numbers</strong> — add your reps to your phone contacts</li></ol>"},{"id":"s3","title":"Power Toolkit","content":"<p>Key lookup tools:</p><ul><li>U.S. House: house.gov/representatives/find-your-representative</li><li>U.S. Senate: senate.gov/senators/senators-contact.htm</li><li>Texas Legislature: capitol.texas.gov/fyi/fyi.aspx</li><li>Houston City Council: houstontx.gov/council</li></ul>"},{"id":"s4","title":"30-Day Action Plan","content":"<p><strong>Week 1:</strong> Research your representatives and their positions on issues you care about.</p><p><strong>Week 2:</strong> Make your first calls. Use the script template. Start with local officials.</p><p><strong>Week 3:</strong> Attend a public meeting — city council, school board, or commissioners court.</p><p><strong>Week 4:</strong> Write a letter to the editor or share your experience on social media. Recruit one friend to take action.</p>"}]'::jsonb),

('GUIDE_007',
 'Call Your Senators',
 'call-your-senators',
 'Contact your U.S. senators about active legislative issues. Includes call scripts, issue summaries, and tips for effective advocacy.',
 'THEME_04',
 'Off the Couch',
 'https://www.thechangelab.net/callyoursenator',
 7,
 '[{"id":"s1","title":"Active Issues","content":"<ul><li><strong>DHS Funding</strong> — Ongoing appropriations crisis</li><li><strong>ACA Premium Spikes</strong> — 20 million people affected by potential premium increases</li><li><strong>Medicaid Work Requirements</strong> — New implementation concerns</li><li><strong>SNAP Benefit Changes</strong> — Affecting adults ages 55–64</li><li><strong>Social Security Administration</strong> — Staffing crisis affecting service delivery</li></ul>"},{"id":"s2","title":"How to Call","content":"<ol><li>Find your senators at senate.gov</li><li>Call during business hours (9 AM – 5 PM ET)</li><li>Ask for the staffer who handles your issue</li><li>State your name, city, and zip code</li><li>Deliver your message in under 90 seconds</li></ol>"},{"id":"s3","title":"Call Script","content":"<p>\"Hi, my name is [NAME] and I''m a constituent from [CITY], Texas, zip code [ZIP]. I''m calling about [ISSUE]. I''d like Senator [NAME] to [YOUR ASK — vote yes/no, cosponsor, hold a hearing]. This matters to me because [BRIEF PERSONAL REASON]. Thank you for your time and please log my call.\"</p>"},{"id":"s4","title":"Tips","content":"<p>Average call time: 90 seconds. You don''t need to be an expert. Staff are trained to listen. Be polite but firm. Always ask them to log your call. If you get voicemail, leave the same message — it still gets counted.</p>"}]'::jsonb);
